const body = $json.body || {};
const rec = body.record || {};
const old = body.old_record || {};
const now = Date.now();

// A breaker is "open" when opened_until is in the future.
const isOpenNow = rec.opened_until && new Date(rec.opened_until).getTime() > now;
const wasClosed = !old.opened_until || new Date(old.opened_until).getTime() <= now;

// Only fire on the transition closed -> open. Any other write returns 0 items
// so the Discord node is skipped for that execution.
if (!(isOpenNow && wasClosed)) {
  return [];
}

const platform = rec.platform || 'unknown';
const fails = (rec.consecutive_failures ?? '?').toString();
const until = rec.opened_until;
const content = `🚨 **Circuit breaker OPEN** · \`${platform}\`\nTripped after ${fails} consecutive failures. Calls to ${platform} are paused until _${until}_.\nCheck the source before the next slate.`;
return [{ json: { content } }];
